body.script:
fetch('feed.rss')  // Change the filename to 'feed.rss' as per your file
    .then(response => response.text())
    .then(data => {
        document.getElementById('rssContent').textContent = data;  // Display raw RSS XML
    })
    .catch(error => {
        document.getElementById('rssContent').textContent = "Error loading sitemap.";  // Error handling
    });
